const text = $input.first().json.message.text || '';
const parts = text.trim().split(/\s+/);
const chatId = String($input.first().json.message.chat.id || '');
const userName = $input.first().json.message.from.first_name || 'Usuario';

// Comando /start
if (parts[0] === '/start') {
  return [{
    json: {
      tipo: 'ayuda',
      chatId,
      userName,
      mensaje: 'Hola ' + userName + '! Soy tu asistente de Web Scraping.\n\nComandos:\n\n/buscar estatico [URL]\n  Auditoria SEO de una web\n\n/buscar estatico [URL] guardar\n  Auditoria SEO + guardar en historico\n\n/buscar dinamico [URL] [producto]\n  Buscar productos con IA (Playwright + Groq)\n\n/buscar dinamico [URL] [producto] guardar\n  Buscar productos + guardar\n\n/reporte\n  Ver resumen del historico\n\nEjemplos:\n/buscar estatico https://es.wikipedia.org\n/buscar dinamico https://mercadolibre.com.co ram\n/buscar dinamico https://mercadolibre.com.co iphone-15 guardar\n\nNota: productos de varias palabras van con guion (memoria-ram)'
    }
  }];
}

// Comando /ayuda o /help
if (parts[0] === '/ayuda' || parts[0] === '/help') {
  return [{
    json: {
      tipo: 'ayuda',
      chatId,
      mensaje: 'COMANDOS DISPONIBLES\n' + '='.repeat(25) + '\n\n/buscar estatico [URL]\n/buscar estatico [URL] guardar\n/buscar dinamico [URL] [producto]\n/buscar dinamico [URL] [producto] guardar\n/reporte\n\nProductos con varias palabras: usar guiones\nEj: memoria-ram, iphone-15-pro'
    }
  }];
}

// Comando /reporte
if (parts[0] === '/reporte') {
  return [{ json: { tipo: 'reporte', chatId, userName } }];
}

// Comando /buscar
if (parts.length < 3 || parts[0] !== '/buscar') {
  return [{
    json: {
      tipo: 'ayuda',
      chatId,
      mensaje: 'Comando no reconocido. Usa /start para ver la ayuda.'
    }
  }];
}

const tipo = parts[1].toLowerCase();
const url = parts[2];
let buscar = '';
let guardar = false;

if (tipo === 'dinamico') {
  buscar = parts[3] || '';
  guardar = (parts[4] || '').toLowerCase() === 'guardar';
  buscar = buscar.replace(/-/g, ' ');
  if (!buscar) {
    return [{
      json: {
        tipo: 'ayuda',
        chatId,
        mensaje: 'Para scraping dinamico necesitas el producto:\n/buscar dinamico [URL] [producto]\n\nEjemplo:\n/buscar dinamico https://mercadolibre.com.co ram'
      }
    }];
  }
} else if (tipo === 'estatico') {
  guardar = (parts[3] || '').toLowerCase() === 'guardar';
} else {
  return [{
    json: {
      tipo: 'ayuda',
      chatId,
      mensaje: 'Tipo no valido. Usa "estatico" o "dinamico".'
    }
  }];
}

return [{
  json: { tipo, url, buscar, guardar, chatId, userName, error: false }
}];

const html = $input.first().json.data || $input.first().json.body || '';
const url = $('Parser de Comando').first().json.url;
const userName = $('Parser de Comando').first().json.userName;

const titleMatch = html.match(/<title[^>]*>(.*?)<\/title>/is);
const titulo = titleMatch ? titleMatch[1].trim() : 'Sin titulo';

const descMatch = html.match(/<meta\s+name=["']description["']\s+content=["'](.*?)["']/is);
const descripcion = descMatch ? descMatch[1].trim() : 'Sin descripcion';

const countTag = (tag) => (html.match(new RegExp('<' + tag + '[\\s>]', 'gi')) || []).length;
const h1 = countTag('h1');
const h2 = countTag('h2');
const h3 = countTag('h3');
const enlaces = (html.match(/<a\s/gi) || []).length;

const textOnly = html
  .replace(/<script[^>]*>[\s\S]*?<\/script>/gi, '')
  .replace(/<style[^>]*>[\s\S]*?<\/style>/gi, '')
  .replace(/<[^>]+>/g, ' ')
  .replace(/\s+/g, ' ')
  .toLowerCase();

const stopWords = new Set(['de','la','el','en','y','a','los','del','las','un','por','con','no','una','su','para','es','al','que','se','lo','como','mas','o','pero','sus','le','ya','the','and','of','to','in','is','it','for','on','with','as','at','this','be','are','an','was','or','not','has','had','from','but']);

const wordFreq = {};
textOnly.split(/\s+/).forEach(word => {
  const clean = word.replace(/[^a-z\u00e1\u00e9\u00ed\u00f3\u00fa\u00f1\u00fc]/g, '');
  if (clean.length > 3 && !stopWords.has(clean)) {
    wordFreq[clean] = (wordFreq[clean] || 0) + 1;
  }
});

const topKeywords = Object.entries(wordFreq)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 10)
  .map(([word, count]) => word + ' (' + count + ')');

const guardar = $('Parser de Comando').first().json.guardar;
const chatId = $('Parser de Comando').first().json.chatId;
const fecha = new Date().toISOString().split('T')[0];

const saveLabel = guardar ? '\n\nGuardado en historico' : '\n\nDatos efimeros (agrega "guardar" al comando para persistir)';

const reporte = 'AUDITORIA WEB\n' + '='.repeat(30) + '\n\nURL: ' + url + '\nTitulo: ' + titulo + '\n\nEstructura de Encabezados:\n  H1: ' + h1 + ' | H2: ' + h2 + ' | H3: ' + h3 + '\n\nTotal de Enlaces: ' + enlaces + '\n\nTop 10 Palabras Clave:\n  ' + topKeywords.join('\n  ') + '\n\nFecha: ' + fecha + saveLabel;

return [{
  json: {
    tipo: 'estatico', url, titulo, descripcion,
    h1, h2, h3, enlaces,
    palabras_clave: topKeywords.map(k => k.split(' (')[0]).join(', '),
    reporte, guardar, chatId, fecha, userName
  }
}];

const resp = $input.first().json;
const query = $('Parser de Comando').first().json.buscar;
const chatId = $('Parser de Comando').first().json.chatId;
const guardar = $('Parser de Comando').first().json.guardar;
const url = $('Parser de Comando').first().json.url;

if (!resp.success) {
  return [{
    json: {
      error: true,
      chatId,
      reporte: 'Error en el scraping:\n' + (resp.error || 'El microservicio no pudo cargar la pagina.') + '\n\nVerifica que:\n1. El microservicio Playwright esta corriendo\n2. ngrok esta activo\n3. La URL del sitio es correcta',
      guardar: false
    }
  }];
}

// Si Playwright ya extrajo productos directamente, usarlos sin pasar por Groq
if (resp.productos && resp.productos.length > 0) {
  const productos = resp.productos;
  const precios = productos.map(p => p.precio).filter(p => p > 0);
  const precioPromedio = precios.length ? Math.round(precios.reduce((a, b) => a + b, 0) / precios.length) : 0;
  const masBarato = precios.length ? Math.min(...precios) : 0;
  const masCaro = precios.length ? Math.max(...precios) : 0;
  const moneda = productos[0].moneda || 'COP';
  const fecha = new Date().toISOString().split('T')[0];
  const productoBarato = productos.find(p => p.precio === masBarato);
  const productoCaro = productos.find(p => p.precio === masCaro);
  const saveLabel = guardar ? '\n\nGuardado en historico' : '\n\nDatos efimeros (agrega guardar para persistir)';
  const reporte = 'REPORTE DE PRODUCTOS\n' + '='.repeat(30) + '\n\nBusqueda: ' + query + '\nFuente: ' + url + '\n\nTotal productos: ' + productos.length + '\n\nPrecio Promedio: $' + precioPromedio.toLocaleString() + ' ' + moneda + '\n\nMas Barato: $' + masBarato.toLocaleString() + ' ' + moneda + '\n  ' + (productoBarato ? productoBarato.titulo.substring(0, 50) : '') + '\n\nMas Caro: $' + masCaro.toLocaleString() + ' ' + moneda + '\n  ' + (productoCaro ? productoCaro.titulo.substring(0, 50) : '') + '\n\nFecha: ' + fecha + saveLabel;
  return [{
    json: {
      tipo: 'dinamico', url, query, productos,
      datosJson: JSON.stringify(productos),
      precioPromedio, masBarato, masCaro,
      totalItems: productos.length,
      reporte, guardar, chatId, fecha, error: false,
      skipGroq: true
    }
  }];
}

// Si no se extrajeron productos, pasar HTML limpio a Groq
const html = resp.html.substring(0, 50000);

return [{
  json: {
    html,
    htmlLength: resp.longitud,
    urlFinal: resp.url_final,
    tituloPage: resp.titulo,
    query, chatId, guardar, url,
    error: false,
    skipGroq: false
  }
}];

