const input = $input.first().json;

// Si los productos ya fueron extraidos por Playwright, pasar directamente
if (input.skipGroq || (input.productos && input.productos.length > 0)) {
  return [{ json: input }];
}

const chatId = $('Verificar Scraping').first().json.chatId;
const query = $('Verificar Scraping').first().json.query;
const url = $('Verificar Scraping').first().json.url;
const guardar = $('Verificar Scraping').first().json.guardar;

// Extraer respuesta del LLM
let llmResponse = '';
if (input.choices && input.choices[0] && input.choices[0].message) {
  llmResponse = input.choices[0].message.content || '';
} else if (input.response) {
  llmResponse = input.response;
} else if (input.text) {
  llmResponse = input.text;
}

let productos = [];
try {
  const cleaned = llmResponse.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  const match = cleaned.match(/\[([\s\S]*?)\]/);
  if (match) {
    productos = JSON.parse('[' + match[1] + ']');
  } else {
    productos = JSON.parse(cleaned);
  }
} catch (e) {
  return [{
    json: {
      error: true,
      reporte: 'La IA no pudo extraer productos.\n\nPosibles causas:\n- El sitio bloquea scraping\n- No hay productos para esa busqueda\n- Formato HTML no reconocido\n\nIntenta con otro producto o URL.',
      chatId, guardar: false, fecha: new Date().toISOString().split('T')[0]
    }
  }];
}

if (!Array.isArray(productos) || productos.length === 0) {
  return [{
    json: {
      error: true,
      reporte: 'No se encontraron productos para "' + query + '".\nIntenta con otro termino de busqueda.',
      chatId, guardar: false, fecha: new Date().toISOString().split('T')[0]
    }
  }];
}

const precios = productos
  .map(p => parseFloat(String(p.precio).replace(/[^\d.]/g, '')))
  .filter(p => !isNaN(p) && p > 0);

const precioPromedio = precios.length ? Math.round(precios.reduce((a, b) => a + b, 0) / precios.length) : 0;
const masBarato = precios.length ? Math.min(...precios) : 0;
const masCaro = precios.length ? Math.max(...precios) : 0;

const moneda = productos[0].moneda || 'COP';
const fecha = new Date().toISOString().split('T')[0];

const productoBarato = productos.find(p => parseFloat(String(p.precio).replace(/[^\d.]/g, '')) === masBarato);
const productoCaro = productos.find(p => parseFloat(String(p.precio).replace(/[^\d.]/g, '')) === masCaro);

const saveLabel = guardar ? '\n\nGuardado en historico' : '\n\nDatos efimeros (agrega "guardar" para persistir)';

const reporte = 'REPORTE DE PRODUCTOS\n' + '='.repeat(30) + '\n\nBusqueda: ' + query + '\nFuente: ' + url + '\n\nTotal productos: ' + productos.length + '\n\nPrecio Promedio: $' + precioPromedio.toLocaleString() + ' ' + moneda + '\n\nMas Barato: $' + masBarato.toLocaleString() + ' ' + moneda + '\n  ' + (productoBarato ? productoBarato.titulo.substring(0, 50) : '') + '\n\nMas Caro: $' + masCaro.toLocaleString() + ' ' + moneda + '\n  ' + (productoCaro ? productoCaro.titulo.substring(0, 50) : '') + '\n\nFecha: ' + fecha + saveLabel;

return [{
  json: {
    tipo: 'dinamico', url, query, productos,
    datosJson: JSON.stringify(productos),
    precioPromedio, masBarato, masCaro,
    totalItems: productos.length,
    reporte, guardar, chatId, fecha, error: false
  }
}];

const chatId = $('Parser de Comando').first().json.chatId;
const userName = $('Parser de Comando').first().json.userName;

let totalEstaticos = 0;
let totalDinamicos = 0;
let ultimosEstaticos = [];
let ultimosDinamicos = [];

try {
  const estaticos = $('Leer Estaticos').all();
  totalEstaticos = estaticos.length;
  ultimosEstaticos = estaticos.slice(-3).map(item => {
    const j = item.json;
    return '  ' + (j.Fecha || 'N/A') + ' | ' + (j.URL || 'N/A').substring(0, 35) + ' | ' + (j.Titulo || 'N/A').substring(0, 25);
  });
} catch(e) {}

try {
  const dinamicos = $('Leer Dinamicos').all();
  totalDinamicos = dinamicos.length;
  ultimosDinamicos = dinamicos.slice(-3).map(item => {
    const j = item.json;
    return '  ' + (j.Fecha || j['Fecha '] || 'N/A') + ' | ' + (j.Query_buscado || j.Query_Buscado || 'N/A') + ' en ' + (j.URL_Origen || 'N/A').substring(0, 25);
  });
} catch(e) {}

const total = totalEstaticos + totalDinamicos;
const fecha = new Date().toISOString().split('T')[0];

let reporte = 'REPORTE DE HISTORICO\n' + '='.repeat(30) + '\n\nHola ' + userName + '!\n\nTotal registros: ' + total + '\n  Auditorias SEO: ' + totalEstaticos + '\n  Busquedas E-commerce: ' + totalDinamicos + '\n';

if (ultimosEstaticos.length > 0) {
  reporte += '\nUltimas auditorias:\n' + ultimosEstaticos.join('\n') + '\n';
}
if (ultimosDinamicos.length > 0) {
  reporte += '\nUltimas busquedas:\n' + ultimosDinamicos.join('\n') + '\n';
}

reporte += '\nFecha: ' + fecha + '\n\nDashboard: http://localhost:8501';

return [{ json: { reporte, chatId } }];
